Rule.Source:
  import sailpoint.object.AttributeMetaData;
  import sailpoint.object.Identity;

  private boolean isUserSuppliedSource(Identity identity, String identityAttribute) {

    //Check to determine if the AttributeMetaData for a particular Identity Attribute indicates that it was added to the Identity due to internal user modification.

    boolean isUserSuppliedSource = false;
    AttributeMetaData metadata = null;

    if (identity != null) {

      if (identity.getAttributeMetaData(identityAttribute) != null) {

        metadata = identity.getAttributeMetaData(identityAttribute);

        if (metadata.getModified() != null && metadata.getUser() != null) {

          isUserSuppliedSource = true;

        }

      }

    }

    return isUserSuppliedSource;

  }
